code = """import json

# Load civic documents
x1 = locals()['var_functions.query_db:54']
civic_docs = []
if isinstance(x1, str):
    civic_docs = json.load(open(x1))
else:
    civic_docs = list(x1)

# Load funding data  
x2 = locals()['var_functions.query_db:55']
funding = []
if isinstance(x2, str):
    funding = json.load(open(x2))
else:
    funding = list(x2)

# Build funding lookup
funding_lookup = {}
for rec in funding:
    name = rec.get('Project_Name', '').strip()
    if name:
        amount = int(rec.get('Amount', '0'))
        funding_lookup[name] = amount

# Find 2022 disaster projects
total = 0
found_projects = []

# From funding records
for name, amount in funding_lookup.items():
    has_2022 = '2022' in name
    has_disaster = '(FEMA' in name or '(CalOES' in name or '(CalJPIA' in name
    if has_2022 and has_disaster:
        total += amount
        found_projects.append([name, amount])

# Output
result = {
    'total_funding': total,
    'project_count': len(found_projects),
    'projects': found_projects
}

print('__RESULT__:')
print(json.dumps(result))"""

